12	type Item = {
13	  type: string;
14	  material?: string;
15	  enchantment?: number;
16	  cursed?: boolean;
17	};
18	type QuoteStep = { op: "quote"; items: Item[] };
19	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
20	
21	const BLOCK_SIZE = 3;
22	const BLOCK_PREMIUM = 60;
23	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
24	
25	const CURSED_RATE = 0.5;
26	const HIGH_ENCHANTMENT_THRESHOLD = 5;
27	const HIGH_ENCHANTMENT_RATE = 0.3;
28	
29	const isCursed = (item: Item): boolean => item.cursed === true;
30	const isHighlyEnchanted = (item: Item): boolean =>
31	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
32	
33	const SURCHARGE_RULES: { applies: (item: Item) => boolean; rate: number }[] = [
34	  { applies: isCursed, rate: CURSED_RATE },
35	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_RATE },
36	];
37	
38	const groupByType = (items: Item[]): Map<string, Item[]> => {
39	  const groups = new Map<string, Item[]>();
40	  for (const item of items) {
41	    const group = groups.get(item.type) ?? [];
42	    group.push(item);
43	    groups.set(item.type, group);
44	  }
45	  return groups;
46	};
47	
48	const premiumForGroup = (type: string, group: Item[]) => {
49	  if (COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE) {
50	    return BLOCK_PREMIUM;
51	  }
52	  return group.length * BASE_PREMIUM[type];
53	};
54	
55	const itemSurcharges = (item: Item) => {
56	  const base = BASE_PREMIUM[item.type];
57	  return SURCHARGE_RULES.reduce(
58	    (sum, rule) => (rule.applies(item) ? sum + base * rule.rate : sum),
59	    0,
60	  );
61	};
62	
63	const policyBasePremium = (items: Item[]) =>
64	  [...groupByType(items)].reduce(
65	    (total, [type, group]) => total + premiumForGroup(type, group),
66	    0,
67	  );
68	
69	const sumItemSurcharges = (items: Item[]) =>
70	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
71	
72	const FIRST_INSURANCE_RATE = 0.1;
73	
74	const quote = (step: QuoteStep) => {
75	  const policyBase = policyBasePremium(step.items);
76	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
77	  const itemSurchargeTotal = sumItemSurcharges(step.items);
78	  const premium = policyBase + firstInsurance + itemSurchargeTotal;
79	  return { premium: Math.ceil(premium) + PROCESSING_FEE };
80	};
81	
82	export const run = (input: Scenario): unknown => ({
83	  results: input.steps.map(quote),
84	});
